import React from "react";

function Home() {
  return (
    <section className="home">
      <div className="overlay"></div>
      <img src="/images/ch1.jpg" alt="wallpaper"></img>
      <div className="homeContent container">
        <div className="textDiv">
          <span className="smallText">Live Your Life</span>
          <h1 className="homeTitle">In Search Of Incredible</h1>
        </div>
      </div>
    </section>
  );
}

export default Home;
